    t = p["type"]
    if t in PRIMITIVES:
        return f"{p['name']}: {t}"
    m = re.match(r"^Partial<(.+)>$", t)
    if m:
        inner = m.group(1)
        ph = f"${kebab(inner)}"
        refs[ph] = kebab(inner)
        return f"{p['name']}: Partial<{ph}>"
    ph = f"${kebab(t)}"
    refs[ph] = kebab(t)
    return f"{p['name']}: {ph}"


