    m = re.match(r"^(.+)\[\]$", t)
    if m:
        inner = m.group(1)
        ph = f"${kebab(inner)}"
        refs[ph] = kebab(inner)
        return f"{ph}[]"
    m = re.match(r"^(.+) \| null$", t)
    if m:
        inner = m.group(1)
        ph = f"${kebab(inner)}"
        refs[ph] = kebab(inner)
